COPY (SELECT * FROM comp_cast_type AS cct1 WHERE cct1.kind = 'cast') TO '../data/29b/comp_cast_type.csv' (HEADER, DELIMITER ',');
COPY (SELECT * FROM keyword AS k WHERE k.keyword = 'computer-animation') TO '../data/29b/keyword.csv' (HEADER, DELIMITER ',');
COPY (SELECT * FROM role_type AS rt WHERE rt.role = 'actress') TO '../data/29b/role_type.csv' (HEADER, DELIMITER ',');
COPY (SELECT * FROM info_type AS it WHERE it.info = 'release dates') TO '../data/29b/info_type.csv' (HEADER, DELIMITER ',');
COPY (SELECT * FROM movie_info AS mi WHERE mi.info LIKE 'USA:%200%') TO '../data/29b/movie_info.csv' (HEADER, DELIMITER ',');
COPY (SELECT * FROM company_name AS cn WHERE cn.country_code = '[us]') TO '../data/29b/company_name.csv' (HEADER, DELIMITER ',');
COPY (SELECT * FROM comp_cast_type AS cct2 WHERE cct2.kind = 'complete+verified') TO '../data/29b/comp_cast_type.csv' (HEADER, DELIMITER ',');
COPY (SELECT * FROM title AS t WHERE t.title = 'Shrek 2') TO '../data/29b/title.csv' (HEADER, DELIMITER ',');
COPY (SELECT * FROM char_name AS chn WHERE chn.name = 'Queen') TO '../data/29b/char_name.csv' (HEADER, DELIMITER ',');
COPY (SELECT * FROM name AS n WHERE n.gender = 'f' AND n.name LIKE '%An%') TO '../data/29b/name.csv' (HEADER, DELIMITER ',');
COPY (SELECT * FROM info_type AS it3 WHERE it3.info = 'height') TO '../data/29b/info_type.csv' (HEADER, DELIMITER ',');
